sql:
SELECT s.seller_name, b.buyer_name
FROM sellers s
JOIN buyers b ON s.seller_id = b.buyer_id;

SELECT * 
FROM properties
ORDER BY year_built DESC;

SELECT 
  (SELECT COUNT(DISTINCT seller_id) FROM sellers) AS num_sellers, 
  (SELECT COUNT(DISTINCT buyer_id) FROM buyers) AS num_buyers;

SELECT property_id, property_description, property_address
FROM properties
WHERE property_id IN (
  SELECT property_id
  FROM legal_documents
);

external_knowledge:
- 'Individuals' refers to users in the system;
- 'Frequent visits' indicates a high number of access events logged in the access_logs table;
- 'Specified observation period' corresponds to 'start_date' and 'end_date' in the SQL query;
- 'Top five' means selecting the highest five counts based on the number of visits.
